"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[811],{1811:(e,t,i)=>{i.d(t,{AT:()=>r,B$:()=>y,E5:()=>u,G6:()=>c,HQ:()=>o,LS:()=>a,Ld:()=>h,Mt:()=>f,PX:()=>n,Vy:()=>v,Ye:()=>m,Yf:()=>p,dt:()=>d,rR:()=>l,vS:()=>g,wP:()=>s});let n=[{id:1,name:"About",link:"#about"},{id:2,name:"UI/UX Projects",link:"#ui-ux-projects"},{id:3,name:"Testimonials",link:"#testimonials"},{id:4,name:"Other Cases",link:"#others"}],a=[{name:"About",link:"#about"},{name:"Design Process",link:"#design-process"},{name:"KeyScout",link:"#keyscout"},{name:"RawIdea",link:"#rawidea"},{name:"LeadMind agency",link:"#leadmind"},{name:"Testimonials",link:"#testimonials"},{name:"Contact",link:"#footer"}],s=[{name:"linkedin",link:"https://www.linkedin.com/in/george-birman/",icon:"/assets/icons/linkedin.svg"},{name:"telegram",link:"https://t.me/GeoRithm",icon:"/assets/icons/telegram.svg"},{name:"whatsapp",link:"https://wa.me/31614731777",icon:"/assets/icons/reach-out-whatsapp.svg"}],o=[{name:"Figma",icon:"/assets/icons/24.png"},{name:"Notion",icon:"/assets/icons/25.png"},{name:"Adobe",icon:"/assets/icons/24.png"},{name:"WixStudio",icon:"/assets/icons/25.png"},{name:"Zoho",icon:"/assets/icons/24.png"},{name:"Framer",icon:"/assets/icons/25.png"},{name:"CRM",icon:"/assets/icons/24.png"}],r=[{img:"/assets/digits/count-red.jpg",heading:"Step 1: Product design Research",text:"I take the time to understand clients and their vision to help bring their product to life. Using the design thinking process or the Double Diamond framework, I refine ideas through iteration and collaborate with professionals to generate meaningful insights that drive the project forward."},{img:"/assets/digits/count-mix.jpg",heading:"Step 2: UI design and prototyping in figma",text:"Proficient in Tailwind’s style guidelines, I’m adaptable and comfortable working with various design frameworks. I understand when to use rough prototypes and wireframes for early exploration and when to refine designs with pixel-perfect precision for developer handoff. "},{img:"/assets/digits/count-blue.jpg",heading:"Step 3: No-code dev. or collaborative dev",text:"I have a strong independent skill set and hands-on experience with various CMS platforms, starting with WordPress before transitioning to Framer. At the same time, I’m a collaborative team player who understands IT terminology and seamlessly connects with developers and coding professionals."}],d=[{name:"KeyScout.com",id:"keyscout",link:"/keyscout",number:"/assets/digits/Count-1.webp",text:"Creating a subscription-based scraping bot that brings rental listings straight to your fingertips.",img:"/assets/project-thumbnails/Keyscout.png",backgroundColor:"#92ACB9"},{name:"RawIdea.org",id:"rawidea",link:"/rawidea",number:"/assets/digits/Count-2.webp",text:"Rebranding in partnership with talented designers, delivering bold and stunning visuals.",img:"/assets/project-thumbnails/RawIdea.png",backgroundColor:"#59829E"},{name:"LeadMind.agency",id:"leadmind",link:"/leadmind",number:"/assets/digits/Count-3.webp",text:"Shaping agency portfolio, recruiting talent, and empowering design for an independent future.",img:"/assets/project-thumbnails/LeadMind-website-project-2.webp",backgroundColor:"#0C293D"}],l=[{text:"\uD83C\uDFA8 During my internship at LeadMind, George was my mentor. The one-on-one meetings were helpful for me as I received constructive feedback that made me feel more motivated and inspired.",name:"Delia Popa",title:"UX Intern",img:"/assets/covers-profiles/Delia-feedback-4.webp"},{text:"\uD83D\uDD8B️ I can always go to him for feedback. Thanks to George and the rest of the LeadMind team, I really appreciate their company culture, which is built on helping each other. It's an amazing team to work with, providing great feedback and fostering a wonderful atmosphere.",name:"Lorenzo Jagessar",title:"CMD Graduate",img:"/assets/covers-profiles/lorenzo.png"},{text:"\uD83D\uDCAA\uD83C\uDFFB George’s relentless efforts and incredible contributions helped Breadchaser transition from vision to reality. Working together has been a great experience, and there’s still so much more ahead.",name:"Alexander Krut",title:"Dynamic Full-Stack & AI app Developer",img:"/assets/covers-profiles/Alex-feedback-2.webp"},{text:"\uD83C\uDF93 After completing the graduation project, the client was very happy with the results delivered by George. You were a nice student to work with; you were always willing to engage during our program and eager to learn. Continue to develop your skills in the field of UX design. I wish you a successful career ahead.",name:"Fenne van Doorn",title:"Mentor from The Hague University",img:"/assets/covers-profiles/fenne.png"}],c=[{link:"https://www.linkedin.com/in/george-birman/",icon:"/assets/icons/linkedin-footer.png"},{link:"https://t.me/GeoRithm",icon:"/assets/icons/telegram-footer.png"},{link:"https://wa.me/31614731777",icon:"/assets/icons/whatsapp-footer.png"}],h=[{name:"tanaruz",link:"https://tanaruz.boats",video:"/assets/extra-cases/Tanaruz-website-case-1.mp4"},{name:"tanaruzApp",link:"https://apps.apple.com/be/app/tanaruz-app/id1542009376",video:"/assets/extra-cases/tanaruz-app-4.webm"},{name:"vondell",link:"https://vondellaanvastgoed.nl",video:"/assets/extra-cases/vondellaanvastgoed-5.webm"},{name:"reunion",link:"https://reunioninternational.com",video:"/assets/extra-cases/reunion-international-6.webm"},{name:"hestiva",link:"https://hestiva.com",video:"/assets/extra-cases/hestiva-platform-7.webm"},{name:"breadchaser",link:"https://chromewebstore.google.com/detail/breadchaser-custom-networ/mgbijplmiommnaannjomlaiinkhhjblb",video:"/assets/extra-cases/breadchaser-plug-in-8.mp4"}],g=[{title:"research",text:"I started by examining why the previous tool failed and what challenges it faced. To gain insights into market dynamics and user needs, I analysed the real estate market through research platforms, conducted competitor analysis, and identified their unique strengths and successes. Based on these findings, I developed a strategic plan for the platform redesign.",points:["Market Research","Competitor Analysis","Strategy planning","Insights"]},{title:"create",text:"In the ideation phase, I focused on creative problem-solving and developed three initial concepts, which I tested and refined based on user insights. I then created a comprehensive site map to structure the onboarding process and define the product’s overall architecture. One challenge I faced was coming up with a unique and memorable name. After a brainstorming session with eight UX designers, that I had hosted, we decided on the name KeyScout to be the most suitable one for this project case.",points:["Iteration on concepts","Userflow","New logo","Visual Style Guide"]},{title:"test",text:"In the testing phase, I discovered that the onboarding process had flaws that needed a more intuitive and user-friendly approach, almost “dummy proof.” By gathering user data, I identified key areas for improvement. Despite these challenges, I successfully implemented multilingual options for the website and ensured all essential operational tools now run seamlessly.",points:["Content Integration","From Low-Fidelity to High-Fidelity prototyping","User testing"]}],p=[{icon:"/assets/project-thumbnails/borgplaats-icons/lets-icons_materials.svg",heading:"research",text:"I began by analysing the current challenges of the predecessor product and identifying its key pain points. To address these, I hosted a creative workshop with eight designers, where collaborative idea-jamming provided clarity and direction for moving forward. An in-depth competitor analysis revealed valuable insights and highlighted mistakes to avoid, which informed my design decisions. From there, I outlined an initial product framework for how it should be presented to the end user, while continuing to refine the onboarding process."},{icon:"/assets/project-thumbnails/borgplaats-icons/curve.svg",heading:"create",text:"In the design stage, I developed two thematic concepts while closely aligning them with the target audience profile I had created. Drawing on the preferences of the new generation, I aimed for a clean and simple style that still carried a distinctive character. To achieve this, I introduced a cultural mascot of luck, symbolizing warmth and positivity for users embarking on their home search. I emphasized themes of kindness and empathy, inspired by my own experience of struggling to find a rental place, ensuring the design resonated on both a practical and emotional level."},{icon:"/assets/project-thumbnails/borgplaats-icons/switch.svg",heading:"test",text:"I created a co-pilot voucher within the payment gateway platform and distributed it to 50 users. After reaching out to several of them, I received constructive feedback that highlighted issues needing immediate attention. One key insight was the importance of clear communication, as some users struggled to fully understand how the tool operates or overlooked parts of its functionality. Despite this, the product has shown strong potential as since its launch in July 2025 it has gained 80 primary registered users and over 4,000 impressions within the first month. Moving forward, I plan to focus on refining the communication strategy and strengthening user onboarding to ensure long-term adoption."}],m=[{title:"discover",text:"In the Discovery phase for LeadMind, I conducted a comprehensive brief to gather essential project information and performed thorough market research to identify industry trends. I carried out a detailed competitor analysis to pinpoint strengths and weaknesses in the design agency landscape, ensuring a competitive advantage for LeadMind. To achieve these results, I employed a variety of research methods, including stakeholder interviews, usability testing, surveys, and expert reviews. Finally, I collected all necessary technical requirements to effectively address the functional aspects of the project, positioning LeadMind as a leader in the field.",points:["Interviews","Usability testing","Competitor Analysis","Survey Expert","reviewing"]},{title:"define",text:"Through meticulous research, I identified the key challenges the agency was facing at that time. By employing crucial methods such as problem statement creation, user persona development, affinity mapping, and a 'How Might We' workshop, I generated innovative solutions and uncovered solid insights. These insights ultimately guided me in the right direction for addressing LeadMind's unique challenges and opportunities.",points:["Problem statement","User persona","Affinity mapping","HMW workshop"]},{title:"develop",text:"In the Develop stage, I focused on refining LeadMind's brand identity and crafting a comprehensive UX strategy based on insights from the previous stage. I created wireframes to map out the website's structure and flow, then developed a visual style guide closely aligned with LeadMind's brand identity. Subsequently, I designed and implemented components into the first high-fidelity concept, bringing the refined strategy to life in a tangible form.",points:["Wire-frames","Style-guide","Components Concept"]},{title:"deliver",text:"In the Delivery phase, I created high-fidelity prototypes of the LeadMind’s agency website, implementing responsive design and integrating their content to enhance user engagement. I gathered final feedback, refined the design, and proofread the content. Finally, I delivered the necessary assets with documented specifications to developers, ensuring efficient project execution.",points:["High-Fidelity","Prototyping Feedback","session Proofreading","Instruction"]}],u=[{icon:"/assets/project-thumbnails/leadmind/stats.svg",heading:"analysis",text:"Throughout this project as a UX/UI designer, I conducted thorough research, uncovering valuable insights that sparked meaningful discussions with stakeholders. After reaching a consensus on key points, I strategically implemented the necessary elements for the project, leveraging my analysis to inform design decisions. This approach ensured that the final product was both data-driven and aligned with LeadMind's objectives.",headingColor:"#F3F3F3",textColor:"#EFEFEFE5"},{icon:"/assets/project-thumbnails/leadmind/talk.svg",heading:"creative session",text:"I facilitated a well-structured creative session that fostered productive discussions on key design points. One significant point of debate was the pricing section on the website. I firmly advocated for retaining this section, emphasizing its importance in demonstrating transparency for our pricing packages and service offerings. This general agreement laid a solid foundation for our design, ensuring the project could progress effectively and efficiently.",headingColor:"#F3F3F3",textColor:"#EFEFEFE5"},{icon:"/assets/project-thumbnails/leadmind/launch.svg",heading:"execution",text:"After synthesizing the collective data, I refined my concept into a final high-fidelity product and obtained stakeholder approval, ensuring content-design alignment. I provided clear visual and documented instructions to the development team, monitoring their progress throughout implementation. To maintain design integrity, I offered feedback documentation to the developers, guiding them on aligning their code more closely with the intended design.",headingColor:"#F3F3F3",textColor:"#EFEFEFE5"}],f=[{name:"george birman",title:"lead ui/ux designer",portfolio:"UX, Market Research, Strategy, Backlog and Communication with the Stakeholders."},{name:"IVAN KUZNIETSOV",title:"ui/ux designer",portfolio:"UX/UI, Functional Prototyping, Visual Concept."},{name:"Gabriel Obianyor",title:"creative ui/ux designer",portfolio:"Branding, Logo Design.."}],y=[{title:"discovery",text:"In the Discovery phase, we began by conducting a comprehensive brief to gather all essential information about RAW Idea's project goals and expectations. We then carried out thorough market research to understand the 3D technology landscape and identify trends that could position RAW Idea as a leader in the field. To ensure a competitive advantage, we performed a detailed competitor analysis, pinpointing the strengths and weaknesses of other companies in the industry. Finally, we gathered all necessary technical requirements to address the functional aspects of the project effectively.",points:["Brief","Market Research","Competitor Analysis","Technical Requirements","Gathering"]},{title:"strategy",text:"During the Strategy phase, we focused on defining and refining RAW Idea's brand identity to ensure consistency across their digital presence. Our team developed a user experience (UX) strategy and created wireframes to map out the website’s structure and flow, tailored specifically to RAW Idea's needs. We organized and structured the content through information architecture planning, making the website intuitive and easy to navigate for their target audience. Additionally, we created a visual style guide to maintain design consistency throughout the website, aligning it closely with RAW Idea's brand identity.",points:["Brand Identity Definition","UX Strategy and Wireframing","Information Architecture Planning","Visual Style Guide Creation"]},{title:"solutions",text:"In the Solutions phase, we brought all elements together to create the final product. We developed high-fidelity prototypes that allowed RAW Idea to visualize the final design and provide feedback before development began. Our team then implemented responsive web design to ensure a seamless user experience across all devices. We integrated the content provided by RAW Idea into the website, aligning it with the design to enhance user engagement. Finally, we conducted a final design refinement and successfully launched the website, delivering a polished, fully functional product that perfectly met RAW Idea's needs and expectations.",points:["High-Fidelity Prototyping","Responsive Web Design Implementation","Content Integration","Final Design Refinement and Launch"]}],v=[{icon:"/assets/project-thumbnails/rawidea/strategy.svg",heading:"strategy",text:"As for UX part, I was responsible for defining clear project goals and ensuring that the design efforts align with these objectives. I have assisted in setting project timelines, defining deliverables, and estimating the scope of work. Additionally, I collaborate closely with project managers and the developer team to ensure that UX activities are synchronized with overall project milestones and goals."},{icon:"/assets/project-thumbnails/rawidea/marketResearch.svg",heading:"user and market research",text:"I have conducted an extensive user and market research, I have shared all the findings with the team. Research consisted of: Competitor analysis, User pain points, market trends and opportunities for improvement. Furthermore, together we re-evaluated all findings and discussed them within the team. After highlighting the crusial insights, our team was ready to undertake the challenge. "},{icon:"/assets/project-thumbnails/rawidea/stakeholder.svg",heading:"stakeholder communication",text:"I ensured the project stayed on track by keeping stakeholders and developers aligned with deadlines and requirements. I advocated for user needs throughout the design process, ensuring our solutions met both business goals and user expectations. I managed requirements effectively and adjusted strategies as needed to overcome challenges. Additionally, I supported and represented the design team to maintain a cohesive vision and resolve any issues that arose."}]}}]);